"use client";

import * as React from "react";
import { animated, useReducedMotion, useSprings } from "@react-spring/web";
import { cn } from "./utils";
import { useRotationWheel } from "./use-rotation-wheel";

export interface RotationWheelOption<T extends string | number = string> {
  value: T;
  label: React.ReactNode;
}

interface RotationWheelProps<T extends string | number = string> {
  options: RotationWheelOption<T>[];
  value: T;
  onChange: (value: T) => void;
  disabled?: boolean;
  error?: boolean;
  loop?: boolean;
  className?: string;
  itemHeight?: string;
  "aria-label"?: string;
  "aria-labelledby"?: string;
}

const ANGLE_STEP = 12;
const RAD = (ANGLE_STEP * Math.PI) / 180;
const MIN_SNAP_MS = 50;

function relativePosition(
  i: number,
  active: number,
  n: number,
  loop: boolean,
): number {
  if (!loop) return i - active;
  const raw = (i - active + n) % n;
  return raw > n / 2 ? raw - n : raw;
}

function clickConfig(velocity: number): {
  immediate: boolean;
  tension: number;
  friction: number;
} {
  const dt = velocity > 0 ? 32 / velocity : Infinity;
  if (dt < MIN_SNAP_MS) return { immediate: true, tension: 170, friction: 26 };
  const t = MIN_SNAP_MS / dt;
  const tension = Math.round(170 + t * 630);
  const friction = Math.round(2 * Math.sqrt(tension));
  return { immediate: false, tension, friction };
}

function RotationWheelInner<T extends string | number>(
  {
    options,
    value,
    onChange,
    disabled = false,
    error = false,
    loop = options.length >= 6,
    className,
    itemHeight = "2em",
    "aria-label": ariaLabel,
    "aria-labelledby": ariaLabelledBy,
  }: RotationWheelProps<T>,
  forwardedRef: React.ForwardedRef<HTMLDivElement>,
) {
  const n = options.length;
  const idPrefix = React.useId();

  // Resolve value → index
  const activeIndex = React.useMemo(() => {
    const idx = options.findIndex((o) => o.value === value);
    return idx === -1 ? 0 : idx;
  }, [options, value]);

  const handleIndexChange = React.useCallback(
    (index: number) => {
      if (index >= 0 && index < n) {
        onChange(options[index].value);
      }
    },
    [onChange, options, n],
  );

  const { safeIndex, velocity, containerRef, handleKeyDown, handleOptionClick } =
    useRotationWheel({
      count: n,
      activeIndex,
      onIndexChange: handleIndexChange,
      loop,
      disabled,
    });

  React.useImperativeHandle(forwardedRef, () => containerRef.current!);

  const reducedMotion = useReducedMotion();
  const [springs] = useSprings(
    n,
    (i) => {
      const rel = relativePosition(i, safeIndex, n, loop);
      const dist = Math.abs(rel);
      const { immediate: velImmediate, tension, friction } = clickConfig(velocity);
      const immediate = dist > 4 || !!reducedMotion || velImmediate;
      return {
        rotateX: rel * ANGLE_STEP,
        opacity: [1, 0.75, 0.5, 0.25][dist] ?? 0,
        scale: rel === 0 ? 1 : 0.9,
        immediate,
        config: { tension, friction },
      };
    },
    [safeIndex],
  );

  const optionId = (i: number) => `${idPrefix}-option-${i}`;

  if (n === 0) {
    return (
      <div
        ref={containerRef}
        role="listbox"
        aria-disabled="true"
        aria-label={ariaLabel ?? "Selection wheel"}
        className={cn(
          "select-none relative overflow-hidden h-full",
          className,
        )}
      />
    );
  }

  return (
    <div
      ref={containerRef}
      tabIndex={disabled ? undefined : 0}
      onKeyDown={handleKeyDown}
      role="listbox"
      aria-activedescendant={optionId(safeIndex)}
      aria-roledescription="wheel picker"
      aria-label={ariaLabelledBy ? undefined : (ariaLabel ?? "Selection wheel")}
      aria-labelledby={ariaLabelledBy}
      aria-disabled={disabled || undefined}
      aria-invalid={error || undefined}
      className={cn(
        "select-none touch-none relative overflow-hidden outline-none h-full border rounded transition-colors",
        disabled ? "cursor-default opacity-50" : "cursor-grab",
        error ? "border-destructive" : "border-border",
        !disabled && "focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
        className,
      )}
      style={{
        perspective: "64rem",
        ["--rad" as string]: RAD,
        ["--h" as string]: itemHeight,
      }}
    >
      {options.map((option, i) => {
        const rel = relativePosition(i, safeIndex, n, loop);
        const dist = Math.abs(rel);
        const isClickable = !disabled && dist > 0 && dist <= 3;

        return (
          <animated.div
            key={String(option.value)}
            id={optionId(i)}
            role="option"
            aria-selected={i === safeIndex}
            onClick={isClickable ? () => handleOptionClick(i) : undefined}
            style={{
              scale: springs[i].scale,
              rotateX: springs[i].rotateX,
              opacity: springs[i].opacity,
              transformOrigin:
                "center center calc(-1 * calc(var(--h) / var(--rad)))",
              backfaceVisibility: "hidden",
              cursor: isClickable ? "pointer" : undefined,
            }}
            className="absolute -translate-y-1/2 flex items-center justify-center top-1/2 w-full h-[var(--h)]"
          >
            {option.label}
          </animated.div>
        );
      })}
    </div>
  );
}

const RotationWheel = React.forwardRef(RotationWheelInner) as <T extends string | number = string>(
  props: RotationWheelProps<T> & React.RefAttributes<HTMLDivElement>,
) => React.ReactElement;

export { RotationWheel };
export type { RotationWheelProps };

"use client";

import * as React from "react";
import { useDrag, useWheel } from "@use-gesture/react";

const THRESHOLD = 32; // px — ratchet tooth spacing

export interface UseRotationWheelOptions {
  count: number;
  activeIndex: number;
  onIndexChange: (index: number) => void;
  loop: boolean;
  disabled?: boolean;
}

export interface UseRotationWheelReturn {
  /** Clamped active index (safe even if activeIndex is out of bounds) */
  safeIndex: number;
  velocity: number;
  containerRef: React.RefObject<HTMLDivElement | null>;
  handleKeyDown: (e: React.KeyboardEvent) => void;
  handleOptionClick: (index: number) => void;
}

export function useRotationWheel({
  count: n,
  activeIndex,
  onIndexChange,
  loop,
  disabled = false,
}: UseRotationWheelOptions): UseRotationWheelReturn {
  const safeIndex = n === 0 ? 0 : Math.max(0, Math.min(n - 1, activeIndex));
  const velRef = React.useRef(0);
  const containerRef = React.useRef<HTMLDivElement>(null);

  const rotate = React.useCallback(
    (delta: number) => {
      if (n === 0 || disabled) return;
      const next = loop
        ? (safeIndex + delta + n) % n
        : Math.max(0, Math.min(n - 1, safeIndex + delta));
      if (next !== safeIndex) {
        onIndexChange(next);
      }
    },
    [loop, n, safeIndex, onIndexChange, disabled],
  );

  // --- Ratchet accumulator ---
  const acc = React.useRef(0);
  const prevDir = React.useRef(0);

  // --- Inertia ---
  const inertiaTimers = React.useRef<ReturnType<typeof setTimeout>[]>([]);

  function cancelInertia() {
    if (inertiaTimers.current.length > 0) {
      inertiaTimers.current.forEach(clearTimeout);
      inertiaTimers.current = [];
    }
  }

  function applyInertia(v0: number, dir: number) {
    cancelInertia();
    let t = 0;
    for (let k = 0; k < 12; k++) {
      const vk = v0 * Math.exp(-k / 6);
      if (vk < 0.02) break;
      t += THRESHOLD / vk;
      const capturedV = vk;
      inertiaTimers.current.push(
        setTimeout(() => {
          velRef.current = capturedV;
          rotate(dir);
        }, t),
      );
    }
  }

  // --- Shared move handler (ratchet) ---
  function handleMove(dir: number, dY: number, velocity: number) {
    if (disabled) return;
    if (dir !== 0 && dir !== prevDir.current) {
      prevDir.current = dir;
      acc.current = 0;
      return;
    }
    acc.current += Math.abs(dY);
    if (acc.current >= THRESHOLD) {
      acc.current = 0;
      velRef.current = velocity;
      rotate(dir);
    }
  }

  // --- Gesture bindings ---
  useWheel(
    ({ direction: [, dirY], velocity: [, vY], delta: [, dY], event }) => {
      if (disabled) return;
      event.preventDefault();
      handleMove(dirY, dY, Math.abs(vY));
    },
    { target: containerRef, eventOptions: { passive: false } },
  );

  useDrag(
    ({
      direction: [, dirY],
      velocity: [, vY],
      delta: [, dY],
      first: isFirst,
      last,
      tap,
      event,
    }) => {
      if (disabled) return;
      event.preventDefault();
      if (tap) return;
      if (isFirst) {
        acc.current = 0;
        cancelInertia();
      }
      if (last) {
        applyInertia(Math.abs(vY), -dirY);
        return;
      }
      handleMove(-dirY, dY, Math.abs(vY));
    },
    {
      target: containerRef,
      axis: "y",
      filterTaps: false,
      eventOptions: { passive: false },
      pointer: { touch: true, keys: false },
    },
  );

  // --- Keyboard ---
  const handleKeyDown = React.useCallback(
    (e: React.KeyboardEvent) => {
      if (disabled) return;
      if (e.key !== "ArrowDown" && e.key !== "ArrowUp") return;
      e.preventDefault();
      cancelInertia();
      velRef.current = e.repeat ? Infinity : 0;
      rotate(e.key === "ArrowDown" ? 1 : -1);
    },
    [rotate, disabled],
  );

  // --- Tap-to-select ---
  const handleOptionClick = React.useCallback(
    (index: number) => {
      if (disabled || n === 0) return;
      if (index >= 0 && index < n && index !== safeIndex) {
        velRef.current = 0;
        onIndexChange(index);
      }
    },
    [disabled, n, safeIndex, onIndexChange],
  );

  // --- Cleanup inertia on unmount ---
  React.useEffect(() => cancelInertia, []);

  return {
    safeIndex,
    velocity: velRef.current,
    containerRef,
    handleKeyDown,
    handleOptionClick,
  };
}

import { clsx, type ClassValue } from "clsx";
import { twMerge } from "tailwind-merge";

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}
